        }
      ]
    },
    {
      "order": 2,
      "title": "파기름 내고 고추기름 만들기",
      "description": [
        {
          "content": "식용유 2컵을 냄비에 부어주세요.",
          "start": "00:00:12",
          "end": "00:00:16"
        },
        {
          "content": "채 썬 대파를 식용유에 넣어주세요.",
          "start": "00:00:17",
          "end": "00:00:19"
        },
        {
          "content": "파향이 충분히 나오도록 끓이며 저어주세요.",
          "start": "00:00:20",
          "end": "00:00:34"
        },
        {
          "content": "불을 끄고 고춧가루 1컵반을 넣어주세요.",
          "start": "00:00:35",
          "end": "00:00:36"
        }
      ],
      "timerSeconds": 14,
      "scenes": [
        {
          "start": "00:00:28",
          "end": "00:00:32",
          "label": "파향이 충분히 나오도록"
        }
      ]
    },
    {
      "order": 3,
      "title": "고추기름 곱게 거르기",
      "description": [
        {
          "content": "고춧가루를 잘 섞어주세요.",
          "start": "00:00:37",
          "end": "00:00:42"
        },
        {
          "content": "커피필터를 이용해 고추기름을 부어주세요.",
          "start": "00:00:43",
          "end": "00:00:46"
        },
        {
          "content": "커피필터를 통해 고추기름을 곱게 걸러주세요.",
          "start": "00:00:47",
          "end": "00:00:54"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:00:43",
          "end": "00:00:46",
          "label": "커피필터를 이용해"
        }
      ]
    },
    {
      "order": 4,
      "title": "양념장용 재료 손질하기",
      "description": [
        {
          "content": "대파 2대를 쫑쫑 다져주세요.",
          "start": "00:00:55",
          "end": "00:01:06"
        },
        {
          "content": "소고기 300g을 작게 썰어주세요.",
          "start": "00:01:07",
          "end": "00:01:12"
        },
        {
          "content": "커터기를 이용해 소고기를 갈아주세요.",
          "start": "00:01:13",
          "end": "00:01:21"
        },
        {
          "content": "마늘 100g을 다져주세요.",
          "start": "00:01:24",
          "end": "00:01:28"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:00:59",
          "end": "00:01:03",
          "label": "쫑쫑 다져주세요"
        },
        {
          "start": "00:01:08",
          "end": "00:01:11",
          "label": "작게 썰어주세요"
        },
        {
          "start": "00:01:16",
          "end": "00:01:20",
          "label": "소고기를 갈아주세요"
        }
      ]
    },
    {
      "order": 5,
      "title": "고추기름에 재료 넣고 볶기",
      "description": [
        {
          "content": "갈아진 소고기를 그릇에 옮겨 담아주세요.",
          "start": "00:01:22",
          "end": "00:01:23"
        },
        {
          "content": "필터에 거른 고추기름 300ml를 팬에 넣어주세요.",
          "start": "00:01:29",
          "end": "00:01:31"
        },
        {
          "content": "다진 소고기를 팬에 넣어주세요.",
          "start": "00:01:32",
          "end": "00:01:36"
        },
        {
          "content": "다진 마늘과 대파를 팬에 넣어주세요.",
          "start": "00:01:37",
          "end": "00:01:42"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 6,
      "title": "고기가 익을 때까지 볶기",
      "description": [
        {
          "content": "고기가 익을 때까지 충분히 볶아주세요.",
          "start": "00:01:43",
          "end": "00:02:06"
        }
      ],
      "timerSeconds": 23,
      "scenes": [
        {
          "start": "00:02:01",
          "end": "00:02:05",
          "label": "고기가 익을 때까지"
        }
      ]
    },
    {
      "order": 7,
      "title": "순두부 양념장 만들기",
      "description": [
        {
          "content": "불을 끄고 5분 뒤 고춧가루 1컵반을 넣어주세요.",
          "start": "00:02:07",
          "end": "00:02:11"
        },
        {
          "content": "고춧가루를 골고루 섞어주세요.",
          "start": "00:02:12",
          "end": "00:02:17"
        },
        {
          "content": "육수 2T, 간장 3T, 참치액 2T를 넣어주세요.",
          "start": "00:02:18",
          "end": "00:02:25"
        },
        {
          "content": "천일염 3T와 후추 1t를 넣어주세요.",
          "start": "00:02:26",
          "end": "00:02:34"
        }
      ],
      "timerSeconds": 300,
      "scenes": [
        {
          "start": "00:02:09",
          "end": "00:02:11",
          "label": "5분 뒤 고춧가루"
        }
      ]
    },
    {
      "order": 8,
      "title": "양념장 볶아 완성하기",
      "description": [
        {
          "content": "약불에서 소금이 녹도록 저어가며 볶아주세요.",
          "start": "00:02:35",
          "end": "00:02:48"
        }
      ],
      "timerSeconds": 13,
      "scenes": [
        {
          "start": "00:02:44",
          "end": "00:02:47",
          "label": "소금이 녹도록"
        }
      ]
    },
    {
      "order": 9,
      "title": "순두부와 육수 넣고 끓이기",
      "description": [
        {
          "content": "순두부 2봉지를 썰어 냄비에 넣어주세요.",
          "start": "00:02:49",
          "end": "00:02:53"
        },
        {
          "content": "육수 200ml를 부어주세요.",
          "start": "00:02:54",
          "end": "00:02:55"
        },
        {
          "content": "팔팔 끓기 시작하면 순두부를 적당한 크기로 잘라주세요.",
          "start": "00:02:56",
          "end": "00:03:00"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:02:50",
          "end": "00:02:52",
          "label": "순두부 2봉지를 썰어"
        },
        {
          "start": "00:02:57",
          "end": "00:03:00",
          "label": "적당한 크기로 잘라주세요"
        }
      ]
    },
    {
      "order": 10,
      "title": "순두부 소스로 간하기",
      "description": [
        {
          "content": "순두부 소스 2T를 듬뿍 넣어주세요.",
          "start": "00:03:01",
          "end": "00:03:05"
        },
        {
          "content": "소스를 골고루 섞어주세요.",
          "start": "00:03:06",
          "end": "00:03:08"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 11,
      "title": "계란 넣고 익혀 완성하기",
      "description": [
        {
          "content": "계란 3알을 넣어주세요.",
          "start": "00:03:09",
          "end": "00:03:13"
        },
        {
          "content": "뚜껑을 덮고 계란 흰자가 익을 때까지 살짝 끓여주세요.",
          "start": "00:03:14",
          "end": "00:03:18"
        }
      ],
      "timerSeconds": 4,
      "scenes": [
        {
          "start": "00:03:17",
          "end": "00:03:18",
          "label": "계란 흰자가 익을 때까지"
        }
      ]
    },
    {
      "order": 12,
      "title": "완성",
      "description": [
        {
          "content": "완성된 순두부찌개를 국자로 떠서 확인하세요.",
          "start": "00:03:19",
          "end": "00:03:26"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    }
  ],
  "servingTip": "계란 3알을 깨 넣고 뚜껑을 덮어 흰자 테두리가 익었을 때 완성하며, 부족한 간은 소금으로 맞추어 드세요."
}
